<script lang='ts'>import {onMount} from 'svelte';import AppShell from '$lib/components/AppShell.svelte';import PageHeader from '$lib/components/PageHeader.svelte';import AdminSection from '$lib/components/AdminSection.svelte';import AdminStatCard from '$lib/components/AdminStatCard.svelte';import StatusBadge from '$lib/components/StatusBadge.svelte';import {currentUser} from '$lib/stores/user';import {fetchAdminBilling, type AdminBilling} from '$lib/api';import { getErrorMessage } from '$lib/errors';let d:AdminBilling|null=null;let error='';let loading=false;const load=async()=>{loading=true;error='';try{d=await fetchAdminBilling();}catch(error:unknown){error=getErrorMessage(error,'Erreur');}finally{loading=false;}};onMount(load);</script><AppShell>{#if $currentUser?.role!=='admin'}<p>Accès restreint</p>{:else}<PageHeader title="Admin Billing" subtitle="Abonnements et Stripe"/><button on:click={load}>Refresh</button>{#if loading}<p>Chargement…</p>{/if}{#if error}<p>{error}</p>{/if}{#if d}<AdminSection title="Abonnements"><div class="g"><AdminStatCard label="Total" value={String(d?.subscriptions?.total??0)}/><AdminStatCard label="Active" value={String(d?.subscriptions?.active??0)}/><AdminStatCard label="Inactive" value={String(d?.subscriptions?.inactive??0)}/><AdminStatCard label="Pro" value={String(d?.subscriptions?.pro??0)}/><AdminStatCard label="Studio" value={String(d?.subscriptions?.studio??0)}/></div></AdminSection><AdminSection title="MRR"><div class="g"><AdminStatCard label="MRR estimé" value={String((d?.mrr?.estimate_cents??0)/100)}/><AdminStatCard label="Currency" value={d?.mrr?.currency??'EUR'}/><AdminStatCard label="Pro unit price" value={String((d?.mrr?.pro_unit_cents??0)/100)}/><AdminStatCard label="Studio unit price" value={String((d?.mrr?.studio_unit_cents??0)/100)}/></div><p>MRR estimé à partir des plans internes. Ce n’est pas une source comptable officielle Stripe.</p></AdminSection><AdminSection title="Stripe"><p>Configured <StatusBadge status={d?.stripe?.configured?'configured':'not_configured'}/></p><p>Webhook configured <StatusBadge status={d?.stripe?.webhook_configured?'configured':'not_configured'}/></p><p>Price Pro configured <StatusBadge status={d?.stripe?.price_pro_configured?'configured':'not_configured'}/></p><p>Price Studio configured <StatusBadge status={d?.stripe?.price_studio_configured?'configured':'not_configured'}/></p></AdminSection>{/if}{/if}</AppShell><style>.g{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:.6rem}</style>